end

-- ---------------------------------------------------------------------------
-- Figment-percentage check helpers
-- ---------------------------------------------------------------------------
-- Figment checks use a percentage milestone (20/40/60/80/100) rather than
-- per-figment pickups.  The game tracks figment counts per mental world;
-- these thresholds are polled on the game tick and fired once per session.

-- Maps "WorldKey_NNpercent" → location_id for fast lookup.
-- (All entries are already in check_to_id above; this table is a filtered
--  subset used by the figment-polling code to avoid scanning the full table.)
Locations.figment_checks = {}
for key, loc_id in pairs(Locations.check_to_id) do
    if key:find("percent") then
        Locations.figment_checks[key] = loc_id
    end
end

-- ---------------------------------------------------------------------------
-- Check category helpers
-- ---------------------------------------------------------------------------

--- Return true if the check key represents a pickup-style collectible.
--- These are detected by hooking the base collectible Interact/Pickup event.
function Locations.is_pickup_check(check_key)
    return (
        check_key:find("PsiCard")           ~= nil or
        check_key:find("SupplyChests")      ~= nil or
        check_key:find("SupplyKey")         ~= nil or
        check_key:find("PsyChallengeMarkers") ~= nil or
        check_key:find("_Ham_")             ~= nil or
        check_key:find("_HAM")              ~= nil or
        check_key:find("MemoryVault")       ~= nil or
        check_key:find("Nugget")            ~= nil or
        check_key:find("Dufflebag")         ~= nil or
        check_key:find("SteamerTrunk")      ~= nil or
        check_key:find("Hatbox")            ~= nil or
        check_key:find("Suitcase")          ~= nil or
        check_key:find("_check")            ~= nil
    )
end

--- Return true if the check key is a scavenger-hunt collectible.
function Locations.is_scav_hunt_check(check_key)
    local scav_keys = {
        "DayOldSushi_check", "EnemySurveillanceDevice_check",
        "NamePlaque_check",  "DeckOfCards_check",
        "AstronautIceCream_check", "Laserdisc_check",
        "UnexplodedBomb_check",    "PsitaniumKnife_check",
        "Human_Skull_check",       "Novelty_Mug_check",
        "Can_of_Corn_check",       "Switchblade_Hatchet_check",
        "MurderBot_check",         "Beehive_check",
        "VikingHelmet_check",      "Mindswarm_check",
    }
    for _, k in ipairs(scav_keys) do
        if check_key == k then return true end
    end
    return false
end

--- Return true if the check key is a rank-point reward.
function Locations.is_rank_check(check_key)
    return check_key:find("Rank") ~= nil
end

--- Return true if the check key is a shop purchase.
function Locations.is_shop_check(check_key)
    return check_key:find("Otto") ~= nil or check_key:find("Shop") ~= nil
end

--- Return true if the check key is a mental-world story completion.
function Locations.is_story_complete(check_key)
    return check_key:find("StoryComplete") ~= nil
end

return Locations

